	ColorStats = {0, 0, 0}, --deshabilita UseImageStats
   -- |
    UseAnimation = false; --usa emotes
    AssetAnimId = ""; --debes poner el asset id del emote que quieras
	FPSBoost = false; --poop graphics
   -- |
    DuoMode = false; --activalo en las dos cuentas para detectar al carry
    MainAcc = "linda125xd"; --la cuenta a la que se hara tp
