	SpamJarsOnly = false; --no ataca y solo spamea jars
------------------------------------------------------

    AutoStats = {
        Enable = false,
        Add = "Phys-Damage"; --[ "Health-Max", "Ki-Resist", "Phys-Resist", "Ki-Damage", "Phys-Damage", "Ki-Max", "Speed" ]
    };
}
